# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)

es = Elasticsearch([{'host': 'your_host', 'port': 9200}])  # replace with your Elasticsearch host

@app.route('/api/search', methods=['GET'])
def search_products():
    keyword = request.args.get('q')
    if not keyword:
        return jsonify({'error': 'Missing required query parameter: q'}), 400

    body = {
        "query": {
            "match": {
                "name": keyword
            }
        },
        "from": 0,
        "size": 10  # adjust the number of results to return
    }

    try:
        response = es.search(index='products', body=body)
        products = [{'id': hit['_source']['id'], 'name': hit['_source']['name']} for hit in response['hits']['hits']]
        return jsonify({'results': products})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)